import { Component } from '@angular/core';
import { finalize } from 'rxjs';
import { HttpService } from '../http.service';
import { Router } from '@angular/router';
import { User } from './customer.interface';

@Component({
  selector: 'app-customers',
  templateUrl: './customers.component.html',
  styleUrls: ['./customers.component.scss']
})
export class CustomersComponent {

  data: User[] = [];
  customer? : string;


  delete(){

  }


  constructor( private http: HttpService, private router: Router) { }



  ngOnInit(){
       const sub= this.http.get<User[]>('customers').pipe(finalize(() => {
          if (sub.unsubscribe){
            sub.unsubscribe();
          }
           })).subscribe(data => {
               this.data=data
           })

          }

}




    <h4>לקוחות</h4>
    <button class="w3-btn w3-green w3-round w3-block" routerLink="/add-customer" >לקוח חדש<i class="fa far fa-plus-square"></i></button>

    <table class="w3-table w3-striped w3-bordered">
        <thead>
            <tr>
                <th>שם פרטי</th>
                <th>שם משפחה</th>
                <th>טלפון</th>
                <th>אימייל</th>
                <th> x </th>
            </tr>
        </thead>
        <tbody>
            <tr *ngFor="let item of data">
                <td>{{ item.firsName }}</td>
                <td>{{ item.lastName }}</td>
                <td>{{ item.phone }}</td>
                <td>{{ item.email }}</td>
                <td><button class="w3-btn w3-green w3-round"><i class="fa fa-edit" [routerLink]="['/','customers', item.id]"></i></button></td>
                <td><button class="w3-btn w3-red w3-round" (click)="delete()">x</button></td>

            </tr>
        </tbody>
    </table>
